--liquibase formatted sql

--changeset zyre:1

CREATE TABLE "UserType" (
    "id" INT NOT NULL,
    "label" VARCHAR(15) NOT NULL,
    CONSTRAINT "pk_UserType" PRIMARY KEY ("id")
);
INSERT INTO "UserType" ("id", "label") VALUES
(1, 'System'),
(2, 'BackOffice'),
(3, 'Firm'),
(4, 'Client Portal');

CREATE TABLE "User" (
    "id" INT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
    "firstName" VARCHAR(50) NOT NULL,
    "lastName" VARCHAR(50) NOT NULL,
    "middleName" VARCHAR(50),
    "email" VARCHAR(100) NOT NULL,
    "homePhone" VARCHAR(25),
    "cellPhone" VARCHAR(25),
    "timezone" VARCHAR(50) DEFAULT 'America/New_York' NOT NULL,
    "dateFormat" VARCHAR(50) DEFAULT 'MM/DD/YYYY' NOT NULL,
    "lastSuccessfulLogin" TIMESTAMP WITHOUT TIME ZONE,
    "failedLoginAttempts" INT DEFAULT 0,
    "lastLoginAttempt" TIMESTAMP WITHOUT TIME ZONE,
    "externalId" VARCHAR(250),
    "sessionTimeoutMinutes" INT DEFAULT 30 NOT NULL,
    "isActive" BOOLEAN DEFAULT TRUE,
    "userTypeId" INT NOT NULL,
    "createdByUserId" INT,
    "createdAt" TIMESTAMP WITHOUT TIME ZONE,
    "updatedAt" TIMESTAMP WITHOUT TIME ZONE,
    CONSTRAINT "pk_User" PRIMARY KEY ("id"),
    CONSTRAINT "uc_User_email" UNIQUE ("email"),
    CONSTRAINT "fk_UserType_userTypeId_id" FOREIGN KEY ("userTypeId") REFERENCES "UserType" ("id")
);
ALTER TABLE "User" ADD CONSTRAINT "fk_User_createdByUserId_id" FOREIGN KEY ("createdByUserId") REFERENCES "User" ("id");

CREATE TABLE "UserCredentials" (
    "userId" INT NOT NULL,
    "username" VARCHAR(100),
    "password" VARCHAR(250),
    CONSTRAINT "pk_UserCredentials" PRIMARY KEY ("userId"),
    CONSTRAINT "uc_UserCredentials_username" UNIQUE ("username")
);
ALTER TABLE "UserCredentials" ADD CONSTRAINT "fk_UserCredentials_id_userId" FOREIGN KEY ("userId") REFERENCES "User" ("id") ON DELETE CASCADE;

