CREATE TABLE "FirmUser" (
    "userId" INT NOT NULL, -- FK
    "title" VARCHAR(10),
    "SSN" VARCHAR(50),
    "isOwner" BOOLEAN DEFAULT FALSE NOT NULL,
    "loginCount" INT,
    "verificationCode" VARCHAR(255),
    "lastUpdatedBy" INT, -- FK
    "updatedAt" TIMESTAMP WITHOUT TIME ZONE,
    CONSTRAINT "pk_FirmUser" PRIMARY KEY ("userId"),
    CONSTRAINT "fk_FirmUser_userId_id" FOREIGN KEY ("userId") REFERENCES "User" ("id"),
    CONSTRAINT "fk_FirmUser_lastUpdatedBy_id" FOREIGN KEY ("lastUpdatedBy") REFERENCES "User" ("id")
);
COMMENT ON COLUMN "FirmUser"."loginCount" IS 'Total number of successful log-ins for this user';
